const item = $input.first();
const J = item.json || {};

const type = J.type || '';
const type_label = type === 'clock_in' ? 'Entrada' : 'Saída';

let recorded_at_sp = J.recorded_at;
try {
  if (J.recorded_at) {
    const d = new Date(J.recorded_at);
    if (!Number.isNaN(d.getTime())) {
      recorded_at_sp = new Intl.DateTimeFormat('pt-BR', {
        timeZone: 'America/Sao_Paulo',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      }).format(d);
    }
  }
} catch (e) {}

return [{
  json: {
    ...J,
    type_label,
    recorded_at_sp
  }
}];

